commands.handler:
function (args) {
  if (!args || args.length === 0) {
    output.print('Current base branch: ' + state.get(stateKeys.baseBranch));
    return;
  }
  state.set(stateKeys.baseBranch, args[0]);
  output.print('Base branch set to: ' + args[0]);
}

function (args) {
  var valid = ['directory', 'extension', 'logical', 'minimal'];
  if (!args || args.length === 0) {
    output.print('Current strategy: ' + state.get(stateKeys.groupStrategy));
    output.print('Available: ' + valid.join(', '));
    return;
  }
  var s = args[0].toLowerCase();
  if (valid.indexOf(s) === -1) {
    output.print('Unknown strategy: ' + s + '. Available: ' + valid.join(', '));
    return;
  }
  state.set(stateKeys.groupStrategy, s);
  output.print('Grouping strategy set to: ' + s);
}

function (args) {
  if (!args || args.length === 0) {
    output.print('Current max files per split: ' + state.get(stateKeys.maxFilesPerSplit));
    return;
  }
  var n = parseInt(args[0], 10);
  if (isNaN(n) || n < 1) {
    output.print('Invalid number: ' + args[0]);
    return;
  }
  state.set(stateKeys.maxFilesPerSplit, String(n));
  output.print('Max files per split set to: ' + n);
}
